        {"id":"influxdb","name":"InfluxDB Client","libs":["WiFi.h","InfluxDbClient.h"],"lib_deps":["tobiasschuerg/ESP8266 Influxdb@^3.13.2"],
         "header":'#ifndef INFLUXDB_H\n#define INFLUXDB_H\nvoid influx_setup(const char*url,const char*org,const char*bucket,const char*token);\nvoid influx_add_field(const char*measurement,const char*field,float value);\nbool influx_write();\n#endif',
         "source":'#include "influxdb.h"\n#include <WiFi.h>\n#include <InfluxDbClient.h>\nstatic InfluxDBClient*_client=nullptr;\nstatic Point*_point=nullptr;\nvoid influx_setup(const char*url,const char*org,const char*bkt,const char*tok){_client=new InfluxDBClient(url,org,bkt,tok);if(_client->validateConnection())Serial.println("[influx] OK");else Serial.println("[influx] Fail!");}\nvoid influx_add_field(const char*m,const char*f,float v){if(_point)delete _point;_point=new Point(m);_point->addField(f,v);}\nbool influx_write(){if(!_client||!_point)return false;bool ok=_client->writePoint(*_point);delete _point;_point=nullptr;return ok;}'},
        {"id":"telegram_bot","name":"Telegram Bot","libs":["WiFi.h","WiFiClientSecure.h","UniversalTelegramBot.h"],"lib_deps":["witnessmenow/Universal-Arduino-Telegram-Bot@^1.3.0"],
         "header":'#ifndef TELEGRAM_H\n#define TELEGRAM_H\nvoid telegram_setup(const char*token);\nvoid telegram_loop();\nvoid telegram_send(const char*chat_id,const char*msg);\ntypedef void(*telegram_cb)(const char*chat_id,const char*text);\nvoid telegram_on_message(telegram_cb cb);\n#endif',
         "source":'#include "telegram_bot.h"\n#include <WiFi.h>\n#include <WiFiClientSecure.h>\n#include <UniversalTelegramBot.h>\nstatic WiFiClientSecure _sc;\nstatic UniversalTelegramBot*_bot=nullptr;\nstatic telegram_cb _cb=nullptr;\nstatic unsigned long _l=0;\nvoid telegram_setup(const char*tok){_sc.setCACert(TELEGRAM_CERTIFICATE_ROOT);_bot=new UniversalTelegramBot(tok,_sc);Serial.println("[telegram] OK");}\nvoid telegram_loop(){if(millis()-_l<2000||!_bot)return;_l=millis();int n=_bot->getUpdates(_bot->last_message_received+1);for(int i=0;i<n;i++){if(_cb)_cb(_bot->messages[i].chat_id.c_str(),_bot->messages[i].text.c_str());}}\nvoid telegram_send(const char*id,const char*msg){if(_bot)_bot->sendMessage(id,msg,"");}\nvoid telegram_on_message(telegram_cb cb){_cb=cb;}'},
