        {"id":"median_filter","name":"Median Filter","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef MEDIAN_H\n#define MEDIAN_H\nvoid median_setup(uint8_t window);\nfloat median_add(float value);\nfloat median_get();\n#endif',
         "source":'#include "median_filter.h"\n#include <Arduino.h>\n#define MAX_W 32\nstatic float _buf[MAX_W],_sorted[MAX_W];\nstatic uint8_t _w=5,_idx=0,_cnt=0;\nvoid median_setup(uint8_t w){_w=min(w,(uint8_t)MAX_W);_idx=0;_cnt=0;}\nfloat median_add(float v){_buf[_idx]=v;_idx=(_idx+1)%_w;if(_cnt<_w)_cnt++;memcpy(_sorted,_buf,sizeof(float)*_cnt);for(int i=0;i<_cnt-1;i++)for(int j=i+1;j<_cnt;j++)if(_sorted[j]<_sorted[i]){float t=_sorted[i];_sorted[i]=_sorted[j];_sorted[j]=t;}return _sorted[_cnt/2];}\nfloat median_get(){return _sorted[_cnt/2];}'},
        {"id":"exponential_smooth","name":"Exponential Smoothing","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef EXP_SMOOTH_H\n#define EXP_SMOOTH_H\nvoid ema_setup(float alpha);\nfloat ema_add(float value);\nfloat ema_get();\nvoid ema_reset();\n#endif',
         "source":'#include "exponential_smooth.h"\nstatic float _alpha=0.1,_val=0;static bool _first=true;\nvoid ema_setup(float a){_alpha=a;_first=true;}\nfloat ema_add(float v){if(_first){_val=v;_first=false;}else _val=_alpha*v+(1-_alpha)*_val;return _val;}\nfloat ema_get(){return _val;}\nvoid ema_reset(){_first=true;}'},
        {"id":"threshold_alert","name":"Threshold Alert System","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef THRESH_ALERT_H\n#define THRESH_ALERT_H\n#include <Arduino.h>\ntypedef void(*alert_cb)(uint8_t id,float value);\nvoid alert_setup();\nuint8_t alert_add(float low,float high,alert_cb cb);\nvoid alert_check(uint8_t id,float value);\n#endif',
         "source":'#include "threshold_alert.h"\n#define MAX_ALERTS 16\nstatic struct{float lo,hi;alert_cb cb;bool triggered;}_alerts[MAX_ALERTS];\nstatic uint8_t _cnt=0;\nvoid alert_setup(){_cnt=0;}\nuint8_t alert_add(float lo,float hi,alert_cb cb){if(_cnt>=MAX_ALERTS)return 255;_alerts[_cnt]={lo,hi,cb,false};return _cnt++;}\nvoid alert_check(uint8_t id,float v){if(id>=_cnt)return;if((v<_alerts[id].lo||v>_alerts[id].hi)&&!_alerts[id].triggered){_alerts[id].triggered=true;if(_alerts[id].cb)_alerts[id].cb(id,v);}else if(v>=_alerts[id].lo&&v<=_alerts[id].hi){_alerts[id].triggered=false;}}'},
        {"id":"pulse_counter","name":"Pulse Counter","libs":[],"lib_deps":[],"pins":{"signal":25},
         "header":'#ifndef PULSE_CNT_H\n#define PULSE_CNT_H\nvoid pulse_setup(uint8_t pin);\nvoid pulse_loop();\nuint32_t pulse_get_count();\nfloat pulse_get_frequency();\nvoid pulse_reset();\n#endif',
         "source":'#include "pulse_counter.h"\n#include <Arduino.h>\nstatic uint8_t _pin=25;static volatile uint32_t _cnt=0;static float _freq=0;static uint32_t _lastCnt=0;static unsigned long _l=0;\nvoid IRAM_ATTR _pulse_isr(){_cnt++;}\nvoid pulse_setup(uint8_t p){_pin=p;pinMode(p,INPUT_PULLUP);attachInterrupt(p,_pulse_isr,RISING);Serial.printf("[pulse] OK pin=%d\\n",p);}\nvoid pulse_loop(){if(millis()-_l<1000)return;unsigned long dt=millis()-_l;_l=millis();_freq=(float)(_cnt-_lastCnt)*1000.0/dt;_lastCnt=_cnt;}\nuint32_t pulse_get_count(){return _cnt;}\nfloat pulse_get_frequency(){return _freq;}\nvoid pulse_reset(){_cnt=0;_lastCnt=0;}'},
        {"id":"duty_cycle","name":"Duty Cycle Generator","libs":[],"lib_deps":[],"pins":{"output":25},
         "header":'#ifndef DUTY_CYCLE_H\n#define DUTY_CYCLE_H\nvoid duty_setup(uint8_t pin,uint32_t freq);\nvoid duty_set(float percent);\nvoid duty_set_raw(uint16_t value);\nfloat duty_get();\n#endif',
         "source":'#include "duty_cycle.h"\n#include <Arduino.h>\nstatic uint8_t _pin=25;static float _duty=0;\nvoid duty_setup(uint8_t p,uint32_t f){_pin=p;ledcAttach(p,f,12);Serial.printf("[duty] OK pin=%d freq=%lu\\n",p,(unsigned long)f);}\nvoid duty_set(float pct){_duty=constrain(pct,0,100);ledcWrite(_pin,(uint16_t)(_duty/100.0*4095));}\nvoid duty_set_raw(uint16_t v){ledcWrite(_pin,v);_duty=v/4095.0*100;}\nfloat duty_get(){return _duty;}'},
        {"id":"adc_dma","name":"ADC with DMA (Fast Sampling)","libs":[],"lib_deps":[],"pins":{"analog":36},
         "header":'#ifndef ADC_DMA_H\n#define ADC_DMA_H\n#include <Arduino.h>\nvoid adc_dma_setup(uint8_t pin,uint32_t sample_rate);\nvoid adc_dma_read(int16_t*buffer,size_t count);\nfloat adc_dma_get_max();\nfloat adc_dma_get_rms();\n#endif',
         "source":'#include "adc_dma.h"\n#include <driver/adc.h>\nstatic uint8_t _pin=36;\nvoid adc_dma_setup(uint8_t p,uint32_t sr){_pin=p;analogReadResolution(12);Serial.printf("[adc_dma] OK pin=%d rate=%lu\\n",p,(unsigned long)sr);}\nvoid adc_dma_read(int16_t*buf,size_t n){for(size_t i=0;i<n;i++)buf[i]=analogRead(_pin);}\nfloat adc_dma_get_max(){float mx=0;for(int i=0;i<64;i++){float v=analogRead(_pin);if(v>mx)mx=v;}return mx*3.3/4095.0;}\nfloat adc_dma_get_rms(){float sum=0;for(int i=0;i<64;i++){float v=analogRead(_pin);sum+=v*v;}return sqrt(sum/64)*3.3/4095.0;}'},
        {"id":"interpolation","name":"Linear Interpolation","libs":[],"lib_deps":[],"pins":{},
         "header":'#ifndef INTERP_H\n#define INTERP_H\nfloat lerp(float a,float b,float t);\nfloat map_range(float val,float in_min,float in_max,float out_min,float out_max);\nfloat clamp(float val,float mn,float mx);\nfloat smooth_step(float edge0,float edge1,float x);\n#endif',
         "source":'#include "interpolation.h"\nfloat lerp(float a,float b,float t){return a+(b-a)*t;}\nfloat map_range(float v,float imn,float imx,float omn,float omx){return omn+(v-imn)*(omx-omn)/(imx-imn);}\nfloat clamp(float v,float mn,float mx){return v<mn?mn:(v>mx?mx:v);}\nfloat smooth_step(float e0,float e1,float x){float t=clamp((x-e0)/(e1-e0),0,1);return t*t*(3-2*t);}'},
