        {"id":"neopixel_ring","name":"NeoPixel Ring","libs":["Adafruit_NeoPixel.h"],"lib_deps":["adafruit/Adafruit NeoPixel@^1.12.0"],"pins":{"data":16},
         "header":'#ifndef NEOPIXEL_RING_H\n#define NEOPIXEL_RING_H\nvoid neo_ring_setup(uint16_t num);\nvoid neo_ring_set(uint16_t i,uint8_t r,uint8_t g,uint8_t b);\nvoid neo_ring_fill(uint8_t r,uint8_t g,uint8_t b);\nvoid neo_ring_rainbow();\nvoid neo_ring_progress(uint8_t pct,uint8_t r,uint8_t g,uint8_t b);\nvoid neo_ring_clear();\n#endif',
         "source":'#include "neopixel_ring.h"\n#include <Adafruit_NeoPixel.h>\n#define RING_PIN 16\nstatic Adafruit_NeoPixel*_ring=nullptr;static uint16_t _num=0;\nvoid neo_ring_setup(uint16_t n){_num=n;_ring=new Adafruit_NeoPixel(n,RING_PIN,NEO_GRB+NEO_KHZ800);_ring->begin();_ring->setBrightness(50);_ring->show();Serial.printf("[ring] OK %d LEDs\\n",n);}\nvoid neo_ring_set(uint16_t i,uint8_t r,uint8_t g,uint8_t b){if(_ring&&i<_num){_ring->setPixelColor(i,_ring->Color(r,g,b));_ring->show();}}\nvoid neo_ring_fill(uint8_t r,uint8_t g,uint8_t b){if(_ring){_ring->fill(_ring->Color(r,g,b));_ring->show();}}\nvoid neo_ring_rainbow(){if(!_ring)return;for(uint16_t i=0;i<_num;i++){uint16_t h=(i*65535/_num+millis()*50)&0xFFFF;_ring->setPixelColor(i,_ring->gamma32(_ring->ColorHSV(h)));}_ring->show();}\nvoid neo_ring_progress(uint8_t pct,uint8_t r,uint8_t g,uint8_t b){if(!_ring)return;uint16_t on=_num*pct/100;for(uint16_t i=0;i<_num;i++)_ring->setPixelColor(i,i<on?_ring->Color(r,g,b):0);_ring->show();}\nvoid neo_ring_clear(){if(_ring){_ring->clear();_ring->show();}}'},
        {"id":"st7789_tft","name":"ST7789 TFT 1.54\" SPI","libs":["SPI.h","Adafruit_ST7789.h"],"lib_deps":["adafruit/Adafruit ST7735 and ST7789 Library@^1.10.3","adafruit/Adafruit GFX Library@^1.11.9"],"pins":{"cs":5,"dc":16,"rst":17},
         "header":'#ifndef ST7789_H\n#define ST7789_H\n#include <Adafruit_ST7789.h>\nvoid st7789_setup();\nvoid st7789_clear(uint16_t color);\nvoid st7789_text(int x,int y,const char*text,uint16_t color,int size);\nvoid st7789_fill_rect(int x,int y,int w,int h,uint16_t color);\n#endif',
         "source":'#include "st7789_tft.h"\n#include <SPI.h>\n#include <Adafruit_GFX.h>\nstatic Adafruit_ST7789 tft(5,16,17);\nvoid st7789_setup(){tft.init(240,240);tft.setRotation(2);tft.fillScreen(ST77XX_BLACK);Serial.println("[st7789] OK 240x240");}\nvoid st7789_clear(uint16_t c){tft.fillScreen(c);}\nvoid st7789_text(int x,int y,const char*t,uint16_t c,int s){tft.setCursor(x,y);tft.setTextColor(c);tft.setTextSize(s);tft.print(t);}\nvoid st7789_fill_rect(int x,int y,int w,int h,uint16_t c){tft.fillRect(x,y,w,h,c);}'},
